    public void handleNewSpotOrderBook(Client client, Object message)
    {
        //
        //   {
        //      "channel":"spot.obu",
        //      "result":{
        //         "t":1777275365213,
        //         "full":true,
        //         "s":"ob.XRP_USDT.50",
        //         "u":9649549324,
        //         "b":[
        //            [
        //               "1.414",
        //               "1397.899"
        //            ]
        //         ],
        //         "a":[
        //            [
        //               "1.415",
        //               "17344.926"
        //            ]
        //         ]
        //      },
        //      "time_ms":1777275365214,
        //      "event":"update"
        //   }
        Object result = this.safeDict(message, "result", new java.util.HashMap<String, Object>() {{}});
        Object full = this.safeBool(result, "full", false);
        Object marketIdWithPrefix = this.safeString(result, "s");
        Object marketIdParts = Helpers.split(marketIdWithPrefix, ".");
        Object marketId = this.safeString(marketIdParts, 1);
        Object symbol = this.safeSymbol(marketId, null, "_", "spot");
        Object messageHash = Helpers.add("orderbook:", symbol);
        if (Helpers.isTrue(Helpers.isEqual(this.safeValue(this.orderbooks, symbol), null)))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, 1000));
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        if (Helpers.isTrue(full))
        {
            Object snapshopt = this.parseOrderBook(result, symbol, null, "b", "a");
            Helpers.addElementToObject(snapshopt, "nonce", this.safeInteger(result, "u"));
            Helpers.addElementToObject(snapshopt, "timestamp", this.safeInteger(result, "t"));
            Helpers.callDynamically(orderbook, "reset", new Object[]{snapshopt});
        } else
        {
            Object nonce = this.safeInteger(orderbook, "nonce");
            Object deltaStart = this.safeInteger(result, "u");
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(nonce, null)) || Helpers.isTrue(Helpers.isGreaterThanOrEqual(nonce, deltaStart))))
            {
                return;
            }
            this.handleDelta(orderbook, result);
        }
        client.resolve(orderbook, messageHash);
    }

    public void handleOrderBook(Client client, Object message)
    {
        //
        // spot
        //
        //     {
        //         "time": 1650189272,
        //         "channel": "spot.order_book_update",
        //         "event": "update",
        //         "result": {
        //             "t": 1650189272515,
        //             "e": "depthUpdate",
        //             "E": 1650189272,
        //             "s": "GMT_USDT",
        //             "U": 140595902,
        //             "u": 140595902,
        //             "b": [
        //                 [ '2.51518', "228.119" ],
        //                 [ '2.50587', "1510.11" ],
        //                 [ '2.49944', "67.6" ],
        //             ],
        //             "a": [
        //                 [ '2.5182', "4.199" ],
        //                 [ "2.51926", "1874" ],
        //                 [ '2.53528', "96.529" ],
        //             ]
        //         }
        //     }
        //
        // swap
        //
        //     {
        //         "id": null,
        //         "time": 1650188898,
        //         "channel": "futures.order_book_update",
        //         "event": "update",
        //         "error": null,
        //         "result": {
        //             "t": 1650188898938,
        //             "s": "GMT_USDT",
        //             "U": 1577718307,
        //             "u": 1577719254,
        //             "b": [
        //                 { p: "2.5178", s: 0 },
        //                 { p: "2.5179", s: 0 },
        //                 { p: "2.518", s: 0 },
        //             ],
        //             "a": [
        //                 { p: "2.52", s: 0 },
        //                 { p: "2.5201", s: 0 },
        //                 { p: "2.5203", s: 0 },
        //             ]
        //         }
        //     }
        //
        Object channel = ((String)this.safeString(message, "channel"));
        if (Helpers.isTrue(Helpers.isEqual(channel, "spot.obu")))
        {
            this.handleNewSpotOrderBook(client, message);
            return;
        }
        Object channelParts = Helpers.split(channel, ".");
        Object rawMarketType = this.safeString(channelParts, 0);
        Object isSpot = Helpers.isEqual(rawMarketType, "spot");
        Object marketType = ((Helpers.isTrue(isSpot))) ? "spot" : "contract";
        Object delta = this.safeValue(message, "result");
        Object deltaStart = this.safeInteger(delta, "U");
        Object deltaEnd = this.safeInteger(delta, "u");
        Object marketId = this.safeString(delta, "s");
        Object symbol = this.safeSymbol(marketId, null, "_", marketType);
        Object messageHash = Helpers.add("orderbook:", symbol);
        Object storedOrderBook = this.safeValue(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}));
        Object nonce = this.safeInteger(storedOrderBook, "nonce");
        if (Helpers.isTrue(Helpers.isEqual(nonce, null)))
        {
            Object cacheLength = 0;
            if (Helpers.isTrue(!Helpers.isEqual(storedOrderBook, null)))
            {
                cacheLength = Helpers.getArrayLength(((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache")));
            }
            Object snapshotDelay = this.handleOption("watchOrderBook", "snapshotDelay", 10);
            Object waitAmount = ((Helpers.isTrue(isSpot))) ? snapshotDelay : 0;
            if (Helpers.isTrue(Helpers.isEqual(cacheLength, waitAmount)))
            {
                // max limit is 100
                Object subscription = Helpers.GetValue(client.subscriptions, messageHash);
                Object limit = this.safeInteger(subscription, "limit");
                this.spawn(() -> { try { this.loadOrderBook(client, messageHash, symbol, limit, new java.util.HashMap<String, Object>() {{}}); } catch(Exception _e) { throw new RuntimeException(_e); } }); // needed for c#, number of args needs to match
            }
            ((java.util.List<Object>)((java.util.List<Object>)Helpers.GetValue(storedOrderBook, "cache"))).add(delta);
            return;
        } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(nonce, deltaEnd)))
        {
            return;
        } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(nonce, Helpers.subtract(deltaStart, 1))))
        {
            this.handleDelta(storedOrderBook, delta);
        } else
        {
            ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
            ((java.util.Map<String,Object>)this.orderbooks).remove((String)symbol);
            Object checksum = this.handleOption("watchOrderBook", "checksum", true);
            if (Helpers.isTrue(checksum))
            {
                var error = new ChecksumError(Helpers.add(Helpers.add(this.id, " "), this.orderbookChecksumMessage(symbol)));
                client.reject(error, messageHash);
            }
        }
        client.resolve(storedOrderBook, messageHash);
    }

    public Object getCacheIndex(Object orderBook, Object cache)
    {
        Object nonce = this.safeInteger(orderBook, "nonce");
        Object firstDelta = Helpers.GetValue(cache, 0);
        Object firstDeltaStart = this.safeInteger(firstDelta, "U");
        if (Helpers.isTrue(Helpers.isLessThan(nonce, firstDeltaStart)))
        {
            return Helpers.opNeg(1);
        }
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(cache)); i++)
        {
            Object delta = Helpers.GetValue(cache, i);
            Object deltaStart = this.safeInteger(delta, "U");
            Object deltaEnd = this.safeInteger(delta, "u");
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isGreaterThanOrEqual(nonce, Helpers.subtract(deltaStart, 1)))) && Helpers.isTrue((Helpers.isLessThan(nonce, deltaEnd)))))
            {
                return i;
            }
        }
        return Helpers.getArrayLength(cache);
    }

    public void handleBidAsks(Object bookSide, Object bidAsks)
    {
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(bidAsks)); i++)
        {
            Object bidAsk = Helpers.GetValue(bidAsks, i);
            if (Helpers.isTrue(Helpers.isArray(bidAsk)))
            {
                Helpers.callDynamically(bookSide, "storeArray", new Object[]{this.parseOrderBookBidAsk(bidAsk)});
            } else
            {
                Object price = this.safeFloat(bidAsk, "p");
                Object amount = this.safeFloat(bidAsk, "s");
                Helpers.callDynamically(bookSide, "store", new Object[]{price, amount});
            }
        }
    }

    public void handleDelta(Object orderbook, Object delta)
    {
        Object timestamp = this.safeInteger(delta, "t");
        Helpers.addElementToObject(orderbook, "timestamp", timestamp);
        Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(delta, "u"));
        Object bids = this.safeValue(delta, "b", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object asks = this.safeValue(delta, "a", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object storedBids = Helpers.GetValue(orderbook, "bids");
        Object storedAsks = Helpers.GetValue(orderbook, "asks");
        this.handleBidAsks(storedBids, bids);
        this.handleBidAsks(storedAsks, asks);
    }

