    public void handleTrades(Client client, Object message)
    {
        //
        // {
        //     "time": 1648725035,
        //     "channel": "spot.trades",
        //     "event": "update",
        //     "result": [{
        //       "id": 3130257995,
        //       "create_time": 1648725035,
        //       "create_time_ms": "1648725035923.0",
        //       "side": "sell",
        //       "currency_pair": "LTC_USDT",
        //       "amount": "0.0116",
        //       "price": "130.11"
        //     }]
        // }
        //
        Object result = this.safeValue(message, "result");
        if (!Helpers.isTrue(Helpers.isArray(result)))
        {
            result = new java.util.ArrayList<Object>(java.util.Arrays.asList(result));
        }
        Object parsedTrades = this.parseTrades(result);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(parsedTrades)); i++)
        {
            Object trade = Helpers.GetValue(parsedTrades, i);
            Object symbol = Helpers.GetValue(trade, "symbol");
            Object cachedTrades = this.safeValue(this.trades, symbol);
            if (Helpers.isTrue(Helpers.isEqual(cachedTrades, null)))
            {
                Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
                cachedTrades = new ArrayCache(((Number)limit).intValue());
                Helpers.addElementToObject(this.trades, symbol, cachedTrades);
            }
            Helpers.callDynamically(cachedTrades, "append", new Object[]{trade});
            Object hash = Helpers.add("trades:", symbol);
            client.resolve(cachedTrades, hash);
        }
    }

    /**
     * @method
     * @name gate#watchOHLCV
     * @see https://www.gate.com/docs/developers/apiv4/ws/en/#candlesticks-channel
     * @see https://www.gate.com/docs/developers/futures/ws/en/#candlesticks-api
     * @see https://www.gate.com/docs/developers/delivery/ws/en/#candlesticks-api
     * @description watches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> watchOHLCV(Object symbol2, Object... optionalArgs)
    {
        final Object symbol3 = symbol2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbol = symbol3;
            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            // todo add options support
            Object market = this.market(symbol);
            symbol = Helpers.GetValue(market, "symbol");
            Object marketId = Helpers.GetValue(market, "id");
            Object interval = this.safeString(this.timeframes, timeframe, timeframe);
            Object messageType = this.getTypeByMarket(market);
            Object channel = Helpers.add(messageType, ".candlesticks");
            Object messageHash = Helpers.add(Helpers.add(Helpers.add("candles:", interval), ":"), Helpers.GetValue(market, "symbol"));
            Object url = this.getUrlByMarket(market);
            Object payload = new java.util.ArrayList<Object>(java.util.Arrays.asList(interval, marketId));
            Object ohlcv = (this.subscribePublic(url, messageHash, payload, channel, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(ohlcv, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySinceLimit(ohlcv, since, limit, 0, true);
        });

    }

    public void handleOHLCV(Client client, Object message)
    {
        //
        // {
        //     "time": 1606292600,
        //     "channel": "spot.candlesticks",
        //     "event": "update",
        //     "result": {
        //       "t": "1606292580", // total volume
        //       "v": "2362.32035", // volume
        //       "c": "19128.1", // close
        //       "h": "19128.1", // high
        //       "l": "19128.1", // low
        //       "o": "19128.1", // open
        //       "n": "1m_BTC_USDT" // sub
        //     }
        //   }
        //
        Object channel = ((String)this.safeString(message, "channel"));
        Object channelParts = Helpers.split(channel, ".");
        Object rawMarketType = this.safeString(channelParts, 0);
        Object marketType = ((Helpers.isTrue((Helpers.isEqual(rawMarketType, "spot"))))) ? "spot" : "contract";
        Object result = this.safeValue(message, "result");
        if (!Helpers.isTrue(Helpers.isArray(result)))
        {
            result = new java.util.ArrayList<Object>(java.util.Arrays.asList(result));
        }
        Object marketIds = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(result)); i++)
        {
            Object ohlcv = Helpers.GetValue(result, i);
            Object subscription = this.safeString(ohlcv, "n", "");
            Object parts = Helpers.split(subscription, "_");
            Object timeframeId = this.safeString(parts, 0);
            Object timeframe = this.findTimeframe(timeframeId);
            Object prefix = Helpers.add(timeframe, "_");
            Object marketId = Helpers.replace((String)subscription, (String)prefix, (String)"");
            Object symbol = this.safeSymbol(marketId, null, "_", marketType);
            Object parsed = this.parseOHLCV(ohlcv);
            Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
            Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
            if (Helpers.isTrue(Helpers.isEqual(stored, null)))
            {
                Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
                stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
                Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
            }
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
            Helpers.addElementToObject(marketIds, symbol, timeframe);
        }
        Object keys = Helpers.objectKeys(marketIds);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object symbol = Helpers.GetValue(keys, i);
            Object timeframe = Helpers.GetValue(marketIds, symbol);
            Object interval = this.findTimeframe(timeframe);
            Object hash = Helpers.add(Helpers.add(Helpers.add(Helpers.add("candles", ":"), interval), ":"), symbol);
            Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), interval);
            client.resolve(stored, hash);
        }
    }

    /**
     * @method
     * @name gate#watchMyTrades
     * @see https://www.gate.com/docs/developers/apiv4/ws/en/#user-trades-channel
     * @see https://www.gate.com/docs/developers/futures/ws/en/#user-trades-api
     * @see https://www.gate.com/docs/developers/delivery/ws/en/#user-trades-api
     * @see https://www.gate.com/docs/developers/options/ws/en/#user-trades-channel
     * @description watches information on multiple trades made by the user
     * @param {string} symbol unified market symbol of the market trades were made in
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trade structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object subType = null;
            Object type = null;
            Object marketId = Helpers.add("!", "all");
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                marketId = Helpers.GetValue(market, "id");
            }
            var typeparametersVariable = this.handleMarketTypeAndParams("watchMyTrades", market, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            var subTypeparametersVariable = this.handleSubTypeAndParams("watchMyTrades", market, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object messageType = this.getSupportedMapping(type, new java.util.HashMap<String, Object>() {{
                put( "spot", "spot" );
                put( "margin", "spot" );
                put( "future", "futures" );
                put( "swap", "futures" );
                put( "option", "options" );
            }});
            Object channel = Helpers.add(messageType, ".usertrades");
            Object messageHash = "myTrades";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                messageHash = Helpers.add(messageHash, Helpers.add(":", symbol));
            }
            Object isInverse = (Helpers.isEqual(subType, "inverse"));
            Object url = this.getUrlByMarketType(type, isInverse);
            Object payload = new java.util.ArrayList<Object>(java.util.Arrays.asList(marketId));
            // uid required for non spot markets
            Object requiresUid = (!Helpers.isEqual(type, "spot"));
            Object trades = (this.subscribePrivate(url, messageHash, payload, channel, parameters, requiresUid)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(trades, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(trades, symbol, since, limit, true);
        });

    }

    public void handleMyTrades(Client client, Object message)
    {
        //
        // {
        //     "time": 1543205083,
        //     "channel": "futures.usertrades",
        //     "event": "update",
        //     "error": null,
        //     "result": [
        //       {
        //         "id": "3335259",
        //         "create_time": 1628736848,
        //         "create_time_ms": 1628736848321,
        //         "contract": "BTC_USD",
        //         "order_id": "4872460",
        //         "size": 1,
        //         "price": "40000.4",
        //         "role": "maker"
        //       }
        //     ]
        // }
        //
        Object result = this.safeValue(message, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object tradesLength = Helpers.getArrayLength(result);
        if (Helpers.isTrue(Helpers.isEqual(tradesLength, 0)))
        {
            return;
        }
        Object cachedTrades = this.myTrades;
        if (Helpers.isTrue(Helpers.isEqual(cachedTrades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            cachedTrades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            this.myTrades = cachedTrades;
        }
        Object parsed = this.parseTrades(result);
        Object marketIds = new java.util.HashMap<String, Object>() {{}};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(parsed)); i++)
        {
            Object trade = Helpers.GetValue(parsed, i);
            Helpers.callDynamically(cachedTrades, "append", new Object[]{trade});
            Object symbol = Helpers.GetValue(trade, "symbol");
            Helpers.addElementToObject(marketIds, symbol, true);
        }
        Object keys = Helpers.objectKeys(marketIds);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object market = Helpers.GetValue(keys, i);
            Object hash = Helpers.add("myTrades:", market);
            client.resolve(cachedTrades, hash);
        }
        client.resolve(cachedTrades, "myTrades");
    }

