    public void handleBalance(Client client, Object message)
    {
        //
        // spot order fill
        //     {
        //         "time": 1653664351,
        //         "time_ms": 1605248616763,
        //         "channel": "spot.balances",
        //         "event": "update",
        //         "result": [
        //             {
        //                 "timestamp": "1667556323",
        //                 "timestamp_ms": "1667556323730",
        //                 "user": "1000001",
        //                 "currency": "USDT",
        //                 "change": "0",
        //                 "total": "222244.3827652",
        //                 "available": "222244.3827",
        //                 "freeze": "5",
        //                 "freeze_change": "5.000000",
        //                 "change_type": "order-create"
        //             }
        //         ]
        //     }
        //
        // account transfer
        //
        //    {
        //        "id": null,
        //        "time": 1653665088,
        //        "channel": "futures.balances",
        //        "event": "update",
        //        "error": null,
        //        "result": [
        //          {
        //            "balance": 25.035008537,
        //            "change": 25,
        //            "text": "-",
        //            "time": 1653665088,
        //            "time_ms": 1653665088286,
        //            "type": "dnw",
        //            "user": "10406147"
        //          }
        //        ]
        //   }
        //
        // swap order fill
        //   {
        //       "id": null,
        //       "time": 1653665311,
        //       "channel": "futures.balances",
        //       "event": "update",
        //       "error": null,
        //       "result": [
        //         {
        //           "balance": 20.031873037,
        //           "change": -0.0031355,
        //           "text": "LTC_USDT:165551103273",
        //           "time": 1653665311,
        //           "time_ms": 1653665311437,
        //           "type": "fee",
        //           "user": "10406147"
        //         }
        //       ]
        //   }
        //
        Object result = this.safeValue(message, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Helpers.addElementToObject(this.balance, "info", result);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(result)); i++)
        {
            Object rawBalance = Helpers.GetValue(result, i);
            Object account = this.account();
            Object currencyId = this.safeString(rawBalance, "currency", "USDT"); // when not present it is USDT
            Object code = this.safeCurrencyCode(currencyId);
            Object timestamp = this.safeInteger2(rawBalance, "time_ms", "timestamp_ms");
            Helpers.addElementToObject(this.balance, "timestamp", timestamp);
            Helpers.addElementToObject(this.balance, "datetime", this.iso8601(timestamp));
            Helpers.addElementToObject(account, "used", this.safeString(rawBalance, "freeze"));
            Helpers.addElementToObject(account, "free", this.safeString(rawBalance, "available"));
            Helpers.addElementToObject(account, "total", this.safeString2(rawBalance, "total", "balance"));
            Helpers.addElementToObject(this.balance, code, account);
        }
        Object channel = ((String)this.safeString(message, "channel"));
        Object parts = Helpers.split(channel, ".");
        Object rawType = this.safeString(parts, 0);
        Object channelType = this.getSupportedMapping(rawType, new java.util.HashMap<String, Object>() {{
            put( "spot", "spot" );
            put( "futures", "swap" );
            put( "options", "option" );
        }});
        Object messageHash = Helpers.add(channelType, ".balance");
        this.balance = this.safeBalance(this.balance);
        client.resolve(this.balance, messageHash);
    }

