    public void handleUnSubscribe(Client client, Object message)
    {
        //
        // {
        //     "time":1725534679,
        //     "time_ms":1725534679786,
        //     "id":2,
        //     "conn_id":"fac539b443fd7002",
        //     "trace_id":"efe1d282b630b4aa266b84bee177791a",
        //     "channel":"spot.trades",
        //     "event":"unsubscribe",
        //     "payload":[
        //        "LTC_USDT"
        //     ],
        //     "result":{
        //        "status":"success"
        //     },
        //     "requestId":"efe1d282b630b4aa266b84bee177791a"
        // }
        //
        Object id = this.safeString(message, "id");
        Object keys = Helpers.objectKeys(client.subscriptions);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object messageHash = Helpers.GetValue(keys, i);
            if (!Helpers.isTrue((Helpers.inOp(client.subscriptions, messageHash))))
            {
                continue;
            }
            if (Helpers.isTrue(((String)messageHash).startsWith(((String)"unsubscribe"))))
            {
                Object subscription = Helpers.GetValue(client.subscriptions, messageHash);
                Object subId = this.safeString(subscription, "id");
                if (Helpers.isTrue(!Helpers.isEqual(id, subId)))
                {
                    continue;
                }
                Object messageHashes = this.safeList(subscription, "messageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object subMessageHashes = this.safeList(subscription, "subMessageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(messageHashes)); j++)
                {
                    Object unsubHash = Helpers.GetValue(messageHashes, j);
                    Object subHash = Helpers.GetValue(subMessageHashes, j);
                    this.cleanUnsubscription(client, subHash, unsubHash);
                }
                this.cleanCache(subscription);
            }
        }
    }

    public void handleMessage(Client client, Object message)
    {
        //
        // subscribe
        //    {
        //        "time": 1649062304,
        //        "id": 1649062303,
        //        "channel": "spot.candlesticks",
        //        "event": "subscribe",
        //        "result": { status: "success" }
        //    }
        //
        // candlestick
        //    {
        //        "time": 1649063328,
        //        "channel": "spot.candlesticks",
        //        "event": "update",
        //        "result": {
        //          "t": "1649063280",
        //          "v": "58932.23174896",
        //          "c": "45966.47",
        //          "h": "45997.24",
        //          "l": "45966.47",
        //          "o": "45975.18",
        //          "n": "1m_BTC_USDT",
        //          "a": "1.281699"
        //        }
        //     }
        //
        //  orders
        //   {
        //       "time": 1630654851,
        //       "channel": "options.orders", or futures.orders or spot.orders
        //       "event": "update",
        //       "result": [
        //          {
        //             "contract": "BTC_USDT-20211130-65000-C",
        //             "create_time": 1637897000,
        //               (...)
        //       ]
        //   }
        // orderbook
        //   {
        //       "time": 1649770525,
        //       "channel": "spot.order_book_update",
        //       "event": "update",
        //       "result": {
        //         "t": 1649770525653,
        //         "e": "depthUpdate",
        //         "E": 1649770525,
        //         "s": "LTC_USDT",
        //         "U": 2622525645,
        //         "u": 2622525665,
        //         "b": [
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array]
        //         ],
        //         "a": [
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array], [Array],
        //           [Array]
        //         ]
        //       }
        //     }
        //
        // balance update
        //
        //    {
        //        "time": 1653664351,
        //        "channel": "spot.balances",
        //        "event": "update",
        //        "result": [
        //          {
        //            "timestamp": "1653664351",
        //            "timestamp_ms": "1653664351017",
        //            "user": "10406147",
        //            "currency": "LTC",
        //            "change": "-0.0002000000000000",
        //            "total": "0.09986000000000000000",
        //            "available": "0.09986000000000000000"
        //          }
        //        ]
        //    }
        //
        if (Helpers.isTrue(this.handleErrorMessage(client, message)))
        {
            return;
        }
        Object eventVar = this.safeString(message, "event");
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "subscribe")))
        {
            this.handleSubscriptionStatus(client, message);
            return;
        }
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "unsubscribe")))
        {
            this.handleUnSubscribe(client, message);
            return;
        }
        Object channel = this.safeString(message, "channel", "");
        // after supporting more method we can create a mapping for this
        if (Helpers.isTrue(Helpers.isEqual(channel, "spot.obu")))
        {
            this.handleOrderBook(client, message);
            return;
        }
        Object channelParts = Helpers.split(channel, ".");
        Object channelType = this.safeValue(channelParts, 1);
        Object v4Methods = new java.util.HashMap<String, Object>() {{
            put( "usertrades", "handleMyTrades");
            put( "candlesticks", "handleOHLCV");
            put( "orders", "handleOrder");
            put( "positions", "handlePositions");
            put( "tickers", "handleTicker");
            put( "book_ticker", "handleBidAsk");
            put( "trades", "handleTrades");
            put( "order_book_update", "handleOrderBook");
            put( "balances", "handleBalance");
            put( "liquidates", "handleLiquidation");
        }};
        Object method = this.safeValue(v4Methods, channelType);
        if (Helpers.isTrue(!Helpers.isEqual(method, null)))
        {
            Helpers.callDynamically(this, method, new Object[] {client, message});
        }
        Object requestId = this.safeString(message, "request_id");
        if (Helpers.isTrue(Helpers.isEqual(requestId, "authenticated")))
        {
            this.handleAuthenticationMessage(client, message);
            return;
        }
        if (Helpers.isTrue(!Helpers.isEqual(requestId, null)))
        {
            Object data = this.safeDict(message, "data");
            // use safeValue as result may be Array or an Object
            Object result = this.safeValue(data, "result");
            Object ack = this.safeBool(message, "ack");
            if (Helpers.isTrue(!Helpers.isEqual(ack, true)))
            {
                client.resolve(result, requestId);
            }
        }
    }

